// Normalize draft data, init publish-state accumulators, choose IG image.
const rows = $input.first().json;
const draft = Array.isArray(rows) ? rows[0] : rows;
if (!draft || !draft.id) throw new Error('Draft not found');

const DEFAULT_IMAGE = $env.GHL_DEFAULT_IMAGE_URL
  || 'https://d2xsxph8kpxj0f.cloudfront.net/108053836/GF4NJ2cQF5StX8SHasRdYg/ghl-og-card-BEhHLBVm4Mb4DUN8x68Jgd.png';
const effective_image_url = draft.image_url || DEFAULT_IMAGE;

return [{
  json: {
    ...draft,
    effective_image_url,
    published_platforms: [],
    publish_errors: {},
  }
}];

// Read recent LinkedIn publish history; block if within 4 hours.
const prep = $('Prepare').first().json;
const rows = $input.first().json;
const recent = Array.isArray(rows) ? rows : [];
const skip_linkedin = recent.length > 0;
const linkedin_skip_reason = skip_linkedin
  ? `4h-guard: last LinkedIn post at ${recent[0]?.published_at || 'unknown'}`
  : null;
return [{ json: { ...prep, skip_linkedin, linkedin_skip_reason } }];

// Inspect every platform node's run result and assemble final publish state.
const prep = $('Prepare').first().json;
const guard = $('LI Guard Apply').first().json;

const published = [];
const errors = {};

const readNode = (name) => {
  try { return $(name).first()?.json; } catch { return undefined; }
};

// Facebook: Graph API returns { id: '...' } on success; error has { error: {...} }.
const fb = readNode('Facebook Post');
if (fb && fb.id && !fb.error) published.push('facebook');
else errors.facebook = fb?.error?.message || fb?.error?.error_user_msg || fb?.message || 'unknown error';

// Instagram: require both Create (container id) AND Publish (post id).
const igC = readNode('IG Create Container');
const igP = readNode('IG Publish');
if (igC && igC.id && !igC.error && igP && igP.id && !igP.error) published.push('instagram');
else {
  const msg = igP?.error?.message || igC?.error?.message || igP?.message || igC?.message || 'unknown IG error';
  errors.instagram = msg;
}

// LinkedIn: skipped (4h guard) OR Blotato success.
if (guard.skip_linkedin) {
  errors.linkedin = guard.linkedin_skip_reason || 'skipped by 4h guard';
} else {
  const li = readNode('LinkedIn Post (Blotato)');
  if (li && !li.error) published.push('linkedin');
  else errors.linkedin = li?.error?.message || li?.message || 'unknown LinkedIn error';
}

const all_ok = Object.keys(errors).length === 0;
const status = all_ok ? 'published' : 'partially_published';

return [{
  json: {
    ...prep,
    published_platforms: published,
    publish_errors: errors,
    final_status: status,
    now_iso: new Date().toISOString(),
  }
}];

parameters.jsonBody:
={{ JSON.stringify({
  status: $json.final_status,
  published_at: $json.now_iso,
  updated_at: $json.now_iso,
  published_platforms: $json.published_platforms,
  publish_errors: Object.keys($json.publish_errors).length ? $json.publish_errors : null
}) }}

={{ JSON.stringify({
  chat_id: 1375806243,
  text: (function() {
    const f = $('Compute Final').item.json;
    const ok = f.published_platforms || [];
    const errs = f.publish_errors || {};
    const lines = ['<b>GHL Marketing — publish result</b>'];
    lines.push('Draft: <code>' + f.id + '</code>');
    lines.push('Status: <b>' + f.final_status + '</b>');
    if (ok.length) lines.push('✅ Published: ' + ok.join(', '));
    Object.entries(errs).forEach(([k,v]) => lines.push('❌ ' + k + ': ' + v));
    return lines.join('\n');
  })(),
  parse_mode: 'HTML'
}) }}

parameters.responseBody:
={{ JSON.stringify({
  ok: true,
  draftId: $('Compute Final').item.json.id,
  status: $('Compute Final').item.json.final_status,
  published_platforms: $('Compute Final').item.json.published_platforms,
  publish_errors: $('Compute Final').item.json.publish_errors
}) }}

